var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"역시 멀대 녀석이랑은 보는 눈이 다르구나?","JPN":"やっぱり、ヒョロガリと違って見る目あるんだね？","ENG":"So you're much better judge of character than the Beanstalk is, huh?","TWN":"你的眼光果然和那個傻大個不同呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"확실히 침식체들 때려잡는 일이라면 관리국의 S급 카운터, 이 이수연 님이 최고지.","JPN":"侵食体をぶっ飛ばすことに関しては、管理局のS級カウンター、このカナミ・キズナ様の右に出る者はいないからね。","ENG":"Of course. I'm Lee Sooyeon, Grade S Counter of the Administration, and best of the best when it comes to exterminating C.O.s.","TWN":"確實，說起暴打侵蝕體，最厲害的就是管理局S級制裁者李秀妍大人啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아, 물론 스승님도 빠뜨릴 수 없지만! 스승님은 여리여리해 보여도 정말 강하거든!","JPN":"あっ、もちろん師匠は例外だよ！\\n師匠って、あんなに小っさいのにめちゃくちゃ強いんだから！","ENG":"I mean second best, if we're counting my Master. She may look soft and tender, but she's a fierce warrior!","TWN":"啊，當然不能漏掉師父！師父就算看起來很柔弱，但實際上卻超強的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"나랑 스승님만 계시면 우리 펜릴 전대에 적수는 없었단 말이야.","JPN":"私と師匠さえいれば、フェンリル戦隊は向かうところ敵なしだったんだ。","ENG":"With Master and I, the Fenrir Division was unbeatable.","TWN":"只要有我和師父在，芬里爾戰隊就是無敵的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 멀대? 걘 맨날 뒤에서 이럼 안 되네, 저럼 안 되네 궁시렁거리는 게 일이었다고.","JPN":"えっ？　ヒョロガリのこと？　あいつって、いつも後ろで\\nそれじゃダメ、あれじゃダメってブツブツ言うしか能がなかったよ。","ENG":"Huh? Beanstalk? You have no idea. All he did was complain from behind: you shouldn't do this, you shouldn't do that.","TWN":"什麼？那個傻大個？那傢伙天天都在後面這也不行，那也不行的，煩死人了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님도 멀대 녀석 말을 듣다 보니까 걱정만 많아지셔선...... 나도 어디 가서 안 부끄러운 제자인데.","JPN":"師匠も師匠だよ。私という自慢の弟子がいるんだから、ヒョロガリの言うことなんかいちいち気にしなくていいのに……","ENG":"And Master became more and more worried about me, listening to Beanstalk's ridiculous ideas. I'm a proud apprentice of hers as much as Beanstalk is!","TWN":"聽了那個傻大個的話，害得師父也跟著擔心了起來……明明我也是不管走到哪裡，都不會讓師父丟臉的徒弟啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 괜찮아. 난 언젠가 스승님도 의지하실 만큼 강해질 거거든.","JPN":"ま、平気だけどね。私だって、いつかは師匠に頼ってもらえるくらい強くなるつもりだし。","ENG":"But it's okay. Someday, I'll be strong and Master will count on me more than anyone else.","TWN":"不過，沒關係。總有一天，我會變得強到能讓師父依靠我的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이럴 때 쓰는 말이...... 으음......","JPN":"そういうのを何て言うんだっけ……うーんと……","ENG":"Let's see. What's the proverb people use to describe a situation like this? Hmm...","TWN":"這時候該說……嗯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"맞아, 콩 심은 데 팥 난다!","JPN":"そうそう、確か、出藍の誉れってやつだよ！","ENG":"That's right! An onion will produce a rose!","TWN":"沒錯，種瓜得瓜，種豆得豆！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 우리에게 필요한 건 역할 분담이야.","JPN":"つまりね、私達に必要なのは役割分担だと思うわけ。","ENG":"So we'll need to divide roles and do what we do best!","TWN":"所以，我們要做的就是分工合作。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"사장님은 직접 싸우기 어렵지? 그래도 지금까지처럼 멋지게 지휘해 주면 돼!","JPN":"社長が直接戦うのはまずいでしょう？\\nだから今まで通り、素晴らしい指揮をしてくれてれば大丈夫だよ！","ENG":"You can't go fighting enemies yourself, can you? Then just give out orders!","TWN":"要老闆親自戰鬥會很困難吧？不過，你只要像之前那樣，在後方帥氣地指揮我們就行了！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그럼 침식체는 모두 스승님과의 피나는 수련을 통해 탄생한 내 비장의 기술!","JPN":"侵食体はぜ～んぶ、師匠との血の滲む修行で編み出したとっておきの秘技！","ENG":"I'll let those C.O.s have a taste of the Lee Sooyeon Strike,","TWN":"所有的侵蝕體，我都會用這招和師父一起刻苦修煉後，誕生的秘技——"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이수연 스트라이크로 혼내 줄 테니까!","JPN":"カナミ・キズナストライク！　で、\\n私がコテンパンにしてやるんだから！","ENG":"the ultimate move I developed through painstaking training with Master!","TWN":"\\"李秀妍爆斬\\"打爆它們的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"......응? 부사장 앞에선 절대 그런 말 꺼내지 말라고?","JPN":"……えっ？　副社長の前では絶対に言うなって？　どうして？","ENG":"Huh? You don't want me saying these things when Vice President is around?","TWN":"……嗯？你要我千萬別在副總面前說這種話嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};